import{_ as r,o as t,c as o,a2 as a}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"核心工作流","description":"","frontmatter":{},"headers":[],"relativePath":"product/workflows.md","filePath":"product/workflows.md","lastUpdated":1780508266000}'),i={name:"product/workflows.md"};function s(l,e,c,n,d,m){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="核心工作流" tabindex="-1">核心工作流 <a class="header-anchor" href="#核心工作流" aria-label="Permalink to &quot;核心工作流&quot;">​</a></h1><h2 id="接管已有本地会话" tabindex="-1">接管已有本地会话 <a class="header-anchor" href="#接管已有本地会话" aria-label="Permalink to &quot;接管已有本地会话&quot;">​</a></h2><p>用户在 IM 里发送 <code>/t</code>，bridge 会列出本机可发现的 Codex / Claude Code 会话。用户再发送 <code>/t 1</code> 或点击卡片按钮，就可以把当前聊天绑定到对应本地会话。</p><p>用户价值：</p><ul><li>不需要复制 thread id。</li><li>能从 IM 里看到本机最近会话。</li><li>绑定后直接发消息即可继续同一条会话。</li></ul><p>设计模块：</p><ul><li>本地 runtime 会话发现：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/operator-ui/application/session-source.ts" target="_blank" rel="noreferrer">src/operator-ui/application/session-source.ts</a></li><li>Codex session 索引：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/runtime/codex/session-index.ts" target="_blank" rel="noreferrer">src/runtime/codex/session-index.ts</a></li><li>Claude Code JSONL 发现：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/runtime/claude/session-jsonl.ts" target="_blank" rel="noreferrer">src/runtime/claude/session-jsonl.ts</a></li><li>线程命令：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/session-thread.ts" target="_blank" rel="noreferrer">src/bridge/command/session-thread.ts</a></li></ul><h2 id="在-im-中继续对话" tabindex="-1">在 IM 中继续对话 <a class="header-anchor" href="#在-im-中继续对话" aria-label="Permalink to &quot;在 IM 中继续对话&quot;">​</a></h2><p>聊天绑定到 <code>BridgeSession</code> 后，普通文本会进入当前 runtime。Codex 支持 <code>sdk</code>、<code>pty</code>、<code>tmux</code> provider；Claude Code 支持 <code>pty</code>、<code>sdk</code> provider。</p><p>用户价值：</p><ul><li>同一个 IM 聊天可以从 Codex 切到 Claude Code。</li><li>会话级模型、工作目录、权限模式、sandbox、network 和 reasoning 可以独立覆盖。</li><li>provider 底层差异被隐藏在统一命令和会话模型后面。</li></ul><p>设计模块：</p><ul><li>普通消息进入 runtime：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/turn/interactive/runner.ts" target="_blank" rel="noreferrer">src/bridge/turn/interactive/runner.ts</a></li><li>runtime/provider 命令：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/runtime-settings.ts" target="_blank" rel="noreferrer">src/bridge/command/runtime-settings.ts</a> 和 <a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/provider-settings.ts" target="_blank" rel="noreferrer">src/bridge/command/provider-settings.ts</a></li><li>provider 路由：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/runtime/codex/routing-provider.ts" target="_blank" rel="noreferrer">src/runtime/codex/routing-provider.ts</a></li></ul><h2 id="创建新的-im-群聊会话" tabindex="-1">创建新的 IM 群聊会话 <a class="header-anchor" href="#创建新的-im-群聊会话" aria-label="Permalink to &quot;创建新的 IM 群聊会话&quot;">​</a></h2><p>用户发送 <code>/new</code> 或 <code>/new &lt;名称&gt; &lt;路径&gt;</code>，bridge 会基于当前会话目录创建新的 IM 群聊会话，并把新群绑定到新的 <code>BridgeSession</code>。平台支持时，群名会同步体现用户指定的名称。</p><p>设计模块：</p><ul><li><code>/new</code> 和 <code>/clear</code>：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/session-thread.ts" target="_blank" rel="noreferrer">src/bridge/command/session-thread.ts</a></li><li>表单卡片：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/presentation/index.ts" target="_blank" rel="noreferrer">src/bridge/command/presentation/index.ts</a></li><li>群聊创建/改名能力：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/contracts.ts" target="_blank" rel="noreferrer">src/channels/contracts.ts</a></li><li>飞书实现：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/feishu/adapter.ts" target="_blank" rel="noreferrer">src/channels/feishu/adapter.ts</a></li></ul><h2 id="观察本地会话输出和-mirror" tabindex="-1">观察本地会话输出和 mirror <a class="header-anchor" href="#观察本地会话输出和-mirror" aria-label="Permalink to &quot;观察本地会话输出和 mirror&quot;">​</a></h2><p>当本机 Codex TUI、Codex Native 或 Claude Code 在同一条本地会话里继续输出时，mirror 机制会读取对应 JSONL，把新增 turn 同步到 IM。这样 IM 不只看到自己发起的 prompt，也能看到本地客户端继续产生的结果。</p><p>设计模块：</p><ul><li>mirror 订阅：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/mirror/subscription-registry.ts" target="_blank" rel="noreferrer">src/bridge/mirror/subscription-registry.ts</a></li><li>mirror runtime：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/mirror/runtime.ts" target="_blank" rel="noreferrer">src/bridge/mirror/runtime.ts</a></li><li>turn 合并：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/mirror/turns.ts" target="_blank" rel="noreferrer">src/bridge/mirror/turns.ts</a></li><li>卡片反馈：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/mirror/feedback-controller.ts" target="_blank" rel="noreferrer">src/bridge/mirror/feedback-controller.ts</a></li></ul><h2 id="使用终端、shell-和文件能力" tabindex="-1">使用终端、shell 和文件能力 <a class="header-anchor" href="#使用终端、shell-和文件能力" aria-label="Permalink to &quot;使用终端、shell 和文件能力&quot;">​</a></h2><p>Codex-to-IM 支持几类面向开发工作的远程工具：</p><ul><li><code>/shell [秒数] &lt;command&gt;</code> 在当前会话目录用 <code>codex sandbox</code> 流式执行命令。</li><li><code>/tmux-*</code> 查看、绑定、新建 tmux session，并发送按键。</li><li><code>/pty-screen</code> 查看当前 pty runtime 的屏幕输出。</li><li><code>/cat &lt;path&gt;</code> 打印文件片段。</li><li><code>/file &lt;path&gt;</code> 把本地文件发回 IM。</li></ul><p>设计模块：</p><ul><li>shell 命令：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/shell.ts" target="_blank" rel="noreferrer">src/bridge/command/shell.ts</a></li><li>tmux 命令：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/tmux.ts" target="_blank" rel="noreferrer">src/bridge/command/tmux.ts</a></li><li>pty 屏幕：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/pty.ts" target="_blank" rel="noreferrer">src/bridge/command/pty.ts</a></li><li>文件和附件：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/channels/delivery/artifacts.ts" target="_blank" rel="noreferrer">src/channels/delivery/artifacts.ts</a></li><li>输入安全校验：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/shared/security/validators.ts" target="_blank" rel="noreferrer">src/shared/security/validators.ts</a></li></ul><h2 id="自动任务" tabindex="-1">自动任务 <a class="header-anchor" href="#自动任务" aria-label="Permalink to &quot;自动任务&quot;">​</a></h2><p>用户可以通过 <code>/auto</code> 创建基于时间间隔的自动 prompt，也可以通过 <code>/auto-script</code> 创建脚本驱动的自动任务。脚本任务把 stdout 作为下一轮当前 session runtime prompt。</p><p>设计模块：</p><ul><li>自动任务模型：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/automation/auto-tasks.ts" target="_blank" rel="noreferrer">src/bridge/automation/auto-tasks.ts</a></li><li>自动任务命令：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/command/auto.ts" target="_blank" rel="noreferrer">src/bridge/command/auto.ts</a></li><li>自动任务调度：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/src/bridge/host/manager.ts" target="_blank" rel="noreferrer">src/bridge/host/manager.ts</a></li><li>自动脚本 skill：<a href="https://github.com/zhangle1987/codex-to-im/blob/master/skills/codex-to-im-auto/SKILL.md" target="_blank" rel="noreferrer">skills/codex-to-im-auto/SKILL.md</a></li></ul>',30)])])}const g=r(i,[["render",s]]);export{b as __pageData,g as default};
